mapper.select:
SELECT EXISTS (
    SELECT 1
    FROM posts p
    WHERE p.post_id = #{postId}
      AND p.deleted_at IS NULL
)

SELECT c.comment_id, u.user_id, u.nickname, u.profile_image, c.content, c.like_count, EXISTS( SELECT 1 FROM comment_likes cl WHERE cl.comment_id = c.comment_id AND cl.user_id = #{userId} ) AS liked_by_me, c.created_at, c.parent_id FROM comments c JOIN users u ON u.user_id = c.user_id WHERE c.post_id = #{postId} AND c.parent_id IS NULL AND c.deleted_at IS NULL AND u.deleted_at IS NULL
AND (c.created_at, c.comment_id) < (#{createdAt}, #{commentId})
ORDER BY c.created_at DESC, c.comment_id DESC LIMIT #{size}

SELECT ranked.comment_id, ranked.user_id, ranked.nickname, ranked.profile_image, ranked.content, ranked.like_count, ranked.liked_by_me, ranked.created_at, ranked.parent_id FROM ( SELECT c.comment_id, u.user_id, u.nickname, u.profile_image, c.content, c.like_count, EXISTS( SELECT 1 FROM comment_likes cl WHERE cl.comment_id = c.comment_id AND cl.user_id = #{userId} ) AS liked_by_me, c.created_at, c.parent_id, ROW_NUMBER() OVER ( PARTITION BY c.parent_id ORDER BY c.created_at DESC, c.comment_id DESC ) AS reply_order FROM comments c JOIN users u ON u.user_id = c.user_id WHERE c.parent_id IN
#{parentId}
AND c.deleted_at IS NULL AND u.deleted_at IS NULL ) ranked WHERE ranked.reply_order <= #{limit} ORDER BY ranked.parent_id, ranked.created_at DESC, ranked.comment_id DESC

mapper.delete:
DELETE FROM comment_likes
WHERE comment_id = #{param1}

    OR comment_id IN (
        SELECT c.comment_id
        FROM comments c
        WHERE c.parent_id = #{param1}
          AND c.deleted_at IS NULL
    )

mapper.update:
UPDATE comments
SET deleted_at = CURRENT_TIMESTAMP,
    like_count = 0
WHERE deleted_at IS NULL
  AND (
    comment_id = #{param1}

        OR parent_id = #{param1}

  )
